SELECT
,

FROM yx_notification n
LEFT JOIN yx_user u ON n.sender_id = u.id AND u.is_deleted = FALSE
WHERE n.is_deleted = FALSE
AND n.user_id = #{userId}

    AND n.is_read = #{isRead}

ORDER BY n.created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM yx_notification n
WHERE n.is_deleted = FALSE
AND n.user_id = #{userId}

    AND n.is_read = #{isRead}
